#include <iostream>
#include <string>
#include <vector>
using namespace std;


// 1. АБСТРАКТНИЙ базовий клас (Інтерфейс).
class Enemy {
protected:
    int health;
public:
    Enemy(int hp) : health(hp) {}

    // ВІРТУАЛЬНИЙ МЕТОД: Дозволяє динамічне заміщення
    virtual void attack() {
        cout << "[Базовий Ворог] б'є слабо." << endl;
    }

    // ЧИСТО ВІРТУАЛЬНИЙ МЕТОД: Робить клас Абстрактним! (Не можна створити просто Enemy)
    virtual void showDeath() = 0;

    virtual ~Enemy() {} // ДУЖЕ ВАЖЛИВО! Деструктор завжди має бути virtual
};


// 2. СПАДКОЄМЕЦЬ Гоблін
class Goblin : public Enemy {
public:
    Goblin(int hp) : Enemy(hp) {}

    // Перевизначаємо метод атаки
    void attack() override {
        cout << "[Гоблін] штрикає вас малим кинджалом! (-10 hp)" << endl;
    }

    void showDeath() override {
        cout << "Гоблін із криком падає..." << endl;
    }
};


// 3. СПАДКОЄМЕЦЬ Орк (Броньований Бос)
class Orc : public Enemy {
public:
    Orc(int hp) : Enemy(hp) {}

    void attack() override {
        cout << "[Орк] розмахує важкою СОКИРОЮ! (-50 hp)" << endl;
    }

    void showDeath() override {
        cout << "Орк падає на коліна з глухим гуркотом." << endl;
    }
};


int main() {
    // Enemy e(100);  // ПОМИЛКА! Enemy тепер абстрактний (= 0).

    cout << "=== Масив Ворогів (Покажчики Батька) ===" << endl;
    // Крута фішка ООП: Масив батьківських покажчиків може зберігати БУДЬ-ЯКИХ спадкоємців!
    vector<Enemy*> dungeon;
    dungeon.push_back(new Goblin(100)); // Закидаємо Гобліна
    dungeon.push_back(new Orc(500));    // Закидаємо Орка

    // Ми не знаємо хто є хто. Просто кажемо ВСІМ атакувати!
    for (Enemy* mob : dungeon) {
        // Завдяки VIRTUAL, компілятор сам зрозуміє хто це, і викличе ПРАВИЛЬНИЙ метод.
        mob->attack(); 
    }

    // Симулюємо їхню смерть
    cout << "
==== Перемога Гравця ====" << endl;
    for (Enemy* mob : dungeon) {
        mob->showDeath();
        delete mob; // Правильно звільняємо пам'ять (завдяки virtual ~Enemy)
    }

    return 0;
}
